// Compute "today" and "horizon" for the prompt and filtering.
const horizonDays = 180;
const now = new Date();
const todayISO = now.toISOString().slice(0, 10);
const horizon = new Date(now.getTime() + horizonDays * 24 * 3600 * 1000).toISOString().slice(0, 10);

// Centralized sector definitions for the agent prompt
const sector_definitions = [
  "Disaster Risk Management: Activities, systems, and governance whose primary purpose is to anticipate, reduce, manage, and recover from hazards by strengthening risk assessment, preparedness, emergency response capacity, and disaster recovery coordination.",
  "Basic Infrastructure: Reconstruction or provision of essential public utilities and everyday service infrastructure that keeps settlements functioning, including lifeline networks (energy, water, wastewater, heating, waste, transport, communications) and critical public facilities such as hospitals and other health infrastructure.",
  "Housing: Repair, reconstruction, or development of permanent residential dwellings and residential buildings, focused on restoring safe, adequate, long-term living conditions for households.",
  "Urban Resilience: Integrated city- or neighborhood-level planning, governance, and multi-sector interventions that increase a city’s ability to withstand and adapt to shocks and long-term stresses while improving recovery capacity and overall urban livability."
].join("\n");

return [{
  json: {
    todayISO,
    horizon,
    horizonDays,
    sector_definitions
  }
}];

function stripCodeFences(s) {
  return s.replace(/```(?:json)?\s*([\s\S]*?)\s*```/gi, "$1").trim();
}

function tryParseJson(s) {
  const cleaned = stripCodeFences(String(s || "")).trim();
  if (!cleaned) return null;
  try { return JSON.parse(cleaned); } catch (e) {}
  // Sometimes model returns JSON as a quoted string
  try { return JSON.parse(JSON.parse(cleaned)); } catch (e) {}
  return null;
}

// In AI Agent nodes, the text may be in different places depending on configuration.
// Try a few common ones.
const candidates = [
  $json?.text,
  $json?.output,
  $json?.message,
  $json?.data,
  $json?.result,
  $json,
];

let parsed = null;
for (const c of candidates) {
  if (parsed) break;
  if (typeof c === "string") parsed = tryParseJson(c);
  else if (c && typeof c === "object" && Array.isArray(c.documents)) parsed = c;
}

// If the agent output is already structured (some AI nodes do this)
if (!parsed && Array.isArray($json?.documents)) parsed = $json;

if (!parsed || !Array.isArray(parsed.documents)) {
  throw new Error("Could not parse agent output into { documents: [...] }");
}

return [{ json: { documents: parsed.documents } }];

const crypto = require("crypto");

function normTitle(t) {
  return (t || "")
    .toString()
    .toLowerCase()
    .trim()
    .replace(/\s+/g, " ")
    .replace(/[“”„"]/g, '"')
    .replace(/[’‘]/g, "'")
    .replace(/[‐-‒–—―]/g, "-");
}

function normUrl(u) {
  return (u || "").toString().trim().replace(/\/$/, "");
}

return $input.all().map(item => {
  const j = item.json || {};
  const titleNorm = normTitle(j.title_uk);
  const urlNorm = normUrl(j.source_url);

  const key = `${titleNorm}|${urlNorm}`;
  const hash = crypto.createHash("sha256").update(key, "utf8").digest("hex");

  return {
    json: {
      ...j,
      n8n_doc_title_norm: titleNorm,
      n8n_doc_hash: hash,
      n8n_doc_dedupe_key: key,
    }
  };
});

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

function cleanStr(x) {
  const s = (x ?? "").toString().trim();
  return s.length ? s : null;
}

function normalizeUrl(u) {
  const s = cleanStr(u);
  if (!s) return null;

  try {
    const url = new URL(s);
    // strip common tracking params
    const drop = new Set([
      "utm_source","utm_medium","utm_campaign","utm_term","utm_content",
      "fbclid","gclid","mc_cid","mc_eid"
    ]);
    for (const k of Array.from(url.searchParams.keys())) {
      if (drop.has(k.toLowerCase())) url.searchParams.delete(k);
    }
    // normalize trailing slash
    url.hash = "";
    return url.toString().replace(/\/$/, "");
  } catch (e) {
    return s; // keep raw if URL parsing fails, but still allow flow
  }
}

function normalizeLanguage(x) {
  const s = (cleanStr(x) || "uk").toLowerCase();
  if (["uk","en","de"].includes(s)) return s;
  return "uk";
}

function normalizeTier(x) {
  const n = Number(x);
  if ([1,2,3].includes(n)) return n;
  return 2;
}

function normalizeDocType(x) {
  const s = (cleanStr(x) || "").toLowerCase();
  const allowed = new Set([
    "report","policy-brief","research-paper","white-paper",
    "strategy","guideline","presentation","dataset","other"
  ]);
  if (!s) return null;
  return allowed.has(s) ? s : "other";
}

function normalizeSector(x) {
  const s = (cleanStr(x) || "").toLowerCase();

  // Accept a few common variants from LLMs
  const map = new Map([
    ["basic infrastructure","basic-infrastructure"],
    ["infrastructure","basic-infrastructure"],
    ["basic-infrastructure","basic-infrastructure"],

    ["housing","housing"],

    ["urban resilience","urban-resilience"],
    ["urban-resilience","urban-resilience"],
    ["resilience","urban-resilience"],

    ["disaster risk","disaster-risk-management"],
    ["disaster-risk","disaster-risk-management"],
    ["disaster-risk-management","disaster-risk-management"],
    ["disaster risk management","disaster-risk-management"],
  ]);

  if (map.has(s)) return map.get(s);

  // If unknown, choose a safe default rather than dropping
  return "housing";
}

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};

  const title_uk = cleanStr(j.title_uk);
  const source_url = normalizeUrl(j.source_url);

  // Required fields check
  if (!title_uk || !source_url) {
    // Drop invalid items; alternatively route to a "needs manual" branch
    continue;
  }

  out.push({
    json: {
      title_uk,
      source_url,

      title_en: cleanStr(j.title_en),
      title_de: cleanStr(j.title_de),

      description_uk: cleanStr(j.description_uk),
      description_en: cleanStr(j.description_en),
      description_de: cleanStr(j.description_de),

      original_language: normalizeLanguage(j.original_language),
      document_type: normalizeDocType(j.document_type),

      // keep as string here; we'll wrap to array at POST time
      primary_sector: normalizeSector(j.primary_sector),

      author_stakeholder_id: cleanStr(j.author_stakeholder_id),
      credibility_tier: normalizeTier(j.credibility_tier),
    }
  });
}

return out;

return $input.all().map(i => ({
  json: {
    ...i.json,
    // join key must exist before the Supabase lookup
    dedupe_key: i.json.n8n_title_hash,
  }
}));

// Input: many rows from Supabase, each row has title_uk/title_en/title_de
// Output: single item with all_doc_titles: [ ...unique strings... ]

const titles = new Set();

for (const item of $input.all()) {
  const j = item.json || {};
  for (const k of ["title_uk", "title_en", "title_de"]) {
    const v = (j[k] || "").toString().trim();
    if (v) titles.add(v);
  }
}

return [
  {
    json: {
      all_doc_titles: Array.from(titles),
      existing_title_count: titles.size,
    },
  },
];

